import React from "react";
import { motion, useScroll, useTransform } from "framer-motion";
import DarkModeToggle from "./components/DarkModeToggle";
import { FaGithub, FaLinkedin } from "react-icons/fa";
import background from "./assets/background.JPG";

function App() {
  const { scrollY } = useScroll();
  const backgroundY = useTransform(scrollY, [0, 500], [0, -200]);

  return (
    <div className="relative min-h-screen bg-gradient-to-r from-blue-500 to-purple-600 dark:from-gray-900 dark:to-black text-white">
      {/* Background Parallax */}
      <motion.div
        className="fixed top-0 left-0 w-full h-full bg-cover bg-center z-[-1]"
        style={{
          backgroundImage: `url(${background})`,
          backgroundSize: "cover",
          backgroundAttachment: "fixed",
          y: backgroundY,
        }}
      ></motion.div>

      {/* Navbar */}
      <nav className="fixed top-0 w-full p-6 flex justify-between items-center z-50 
        bg-white/20 dark:bg-black/20 backdrop-blur-md shadow-lg border-b border-gray-300 dark:border-gray-800">
        <h1 className="text-2xl font-bold">Ritesh Chakramani</h1>
        <div className="space-x-6 flex items-center">
          {["About", "Skills", "Projects", "Contact"].map((item) => (
            <a key={item} href={`#${item.toLowerCase()}`} className="hover:text-neon transition">
              {item}
            </a>
          ))}
          <a href="https://github.com/rc-exe" target="_blank" rel="noopener noreferrer">
            <FaGithub className="text-2xl hover:text-gray-400 transition" />
          </a>
          <a href="https://www.linkedin.com/in/ritesh-chakramani-016a0b235" target="_blank" rel="noopener noreferrer">
            <FaLinkedin className="text-2xl hover:text-blue-400 transition" />
          </a>
          <DarkModeToggle />
        </div>
      </nav>

      {/* Hero Section */}
      <main className="p-20 flex flex-col items-center text-center mt-16">
        <motion.h2
          className="text-5xl font-bold text-shadow-glow"
          initial={{ opacity: 0, y: -20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 1 }}
        >
          Hi, I'm <span className="text-neon">Ritesh Chakramani</span> 👋
        </motion.h2>
        <motion.p
          className="mt-4 text-lg max-w-xl"
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ delay: 0.5, duration: 1 }}
        >
          A passionate <strong>Full-Stack Developer</strong> skilled in <strong>React.js & Python</strong>. I build modern, scalable, and high-performance web applications.
        </motion.p>
      </main>

      {/* Sections */}
      {[
        { id: "about", title: "About Me", content: "I specialize in React.js, Python, Flask, and Machine Learning. My goal is to build applications that are intuitive, efficient, and impactful." },
        { id: "skills", title: "Skills", content: "React.js, Java, HTML, JavaScript, Python, Flask, Machine Learning, Tailwind CSS" }
      ].map((section) => (
        <section key={section.id} id={section.id} className="p-10 text-center max-w-3xl mx-auto">
          <h3 className="text-3xl font-semibold mb-4">{section.title}</h3>
          <p className="text-lg">{section.content}</p>
        </section>
      ))}

      {/* Projects Section */}
      <section id="projects" className="p-10 text-center max-w-3xl mx-auto">
        <h3 className="text-3xl font-semibold mb-4">Projects</h3>
        <div className="grid md:grid-cols-2 gap-6">
          {[
            { name: "Online Code Editor", link: "https://online-code-editor-44qz.onrender.com/" },
            { name: "Social Media Dashboard", link: "#" },
            { name: "AI Chatbot", link: "#" },
            { name: "Resume Scanner", link: "#" },
            { name: "Face Recognition Attendance", link: "#" },
          ].map((project) => (
            <motion.a
              key={project.name}
              href={project.link}
              target="_blank"
              rel="noopener noreferrer"
              className="block p-4 bg-gray-200 dark:bg-gray-800 rounded-lg shadow-md hover:shadow-lg transition transform hover:scale-105"
            >
              <strong>{project.name}</strong>
            </motion.a>
          ))}
        </div>
      </section>

      {/* Contact Section */}
      <section id="contact" className="p-10 text-center max-w-3xl mx-auto">
        <h3 className="text-3xl font-semibold mb-4">Contact Me</h3>
        <p className="text-lg">
          📧 Email: <a href="mailto:riteshchakramani123@gmail.com" className="text-neon">riteshchakramani123@gmail.com</a>
        </p>
        <div className="flex justify-center mt-4 space-x-6">
          <a href="https://github.com/rc-exe" target="_blank" rel="noopener noreferrer">
            <FaGithub className="text-3xl hover:text-gray-400 transition" />
          </a>
          <a href="https://www.linkedin.com/in/ritesh-chakramani-016a0b235" target="_blank" rel="noopener noreferrer">
            <FaLinkedin className="text-3xl hover:text-blue-400 transition" />
          </a>
        </div>
      </section>

      {/* Footer */}
      <footer className="p-4 text-center border-t border-gray-500 dark:border-gray-700">
        © 2025 Ritesh Chakramani. All rights reserved.
      </footer>
    </div>
  );
}

export default App;
